embeds.description:
Aquí tienes un ejemplo de JSON para crear una factura electrónica con tributos (percepciones) usando el endpoint de Afip SDK. El campo `Tributos` se incluye como un array dentro de `FECAEDetRequest`, siguiendo la estructura oficial:

```json
{
  "environment": "dev",
  "method": "FECAESolicitar",
  "wsid": "wsfe",
  "params": {
    "Auth": {
      "Token": "TU_TOKEN",
      "Sign": "TU_SIGN",
      "Cuit": "20409378472"
    },
    "FeCAEReq": {
      "FeCabReq": {
        "CantReg": 1,
        "PtoVta": 1,
        "CbteTipo": 6
      },
      "FeDetReq": {
        "FECAEDetRequest": {
          "Concepto": 1,
          "DocTipo": 80,
          "DocNro": 20111111112,
          "CbteDesde": 1,
          "CbteHasta": 1,
          "CbteFch": 20240730,
          "ImpTotal": 200,
          "ImpTotConc": 0,
          "ImpNeto": 150,
          "ImpOpEx": 0,
          "ImpIVA": 21,
          "ImpTrib": 29,
          "MonId": "PES",
          "MonCotiz": 1,
          "Iva": {
            "AlicIva": [
              {
                "Id": 5,
                "BaseImp": 100,
                "Importe": 21
              }
            ]
          },
          "Tributos": [
            {
              "Id": 99,
              "Desc": "DGR",
              "BaseImp": 150,
              "Alic": 5.2,
              "Importe": 7.8
            },
            {
              "Id": 1,
              "Desc": "Impuesto Nacional",
              "BaseImp": 150,
              "Alic": 10,
              "Importe": 15
            },
            {
              "Id": 2,
              "Desc": "Impuesto Provincial",
              "BaseImp": 150,
              "Alic": 4,
              "Importe": 6.2
            }
          ]
        }
      }
    }
  }
}
```
